class Solution {
public:
    void sortColors(vector<int>& a) {
        int lo=0, mid=0, hi=(int)a.size()-1;
        while (mid<=hi) {
            if (a[mid]==0) swap(a[lo++], a[mid++]);
            else if (a[mid]==1) mid++;
            else swap(a[mid], a[hi--]);
        }
    }
};

